import type { Colordx } from "@colordx";

/** Primary color scale with dark (d), medium (m), and light (l) ranges. */
export interface ThemePrimaryColorsNext<TColor = Colordx> {
    d10: TColor;
    d20: TColor;
    d30: TColor;
    d40: TColor;

    m10: TColor;
    m20: TColor;
    m30: TColor;
    m40: TColor;

    l10: TColor;
    l20: TColor;
    l30: TColor;
    l40: TColor;
}

/** 16-color terminal palette. */
export interface ThemePaletteColorsNext<TColor = Colordx> {
    black: TColor;
    gray: TColor;
    darkRed: TColor;
    red: TColor;
    darkGreen: TColor;
    green: TColor;
    darkYellow: TColor;
    yellow: TColor;
    darkBlue: TColor;
    blue: TColor;
    darkMagenta: TColor;
    magenta: TColor;
    darkCyan: TColor;
    cyan: TColor;
    lightGray: TColor;
    white: TColor;
}

/** Semantic feedback colors for UI states. */
export interface ThemeFeedbackColorsNext<TColor = Colordx> {
    negative: TColor;
    success: TColor;
    info: TColor;
    warning: TColor;
}

/** Colors for git-related UI elements. */
export interface ThemeGitColorsNext<TColor = Colordx> {
    add: TColor;
    delete: TColor;
    modify: TColor;
}

/** Minimal accent colors used by MNML collection themes. */
export interface ThemeAccentColorsNext<TColor = Colordx> {
    a10: TColor;
    a20: TColor;
    a30?: TColor;
    a40?: TColor;
}

/** UI color tokens split into background and foreground groups. */
export interface ThemeUiColorsNext<TColor = Colordx> {
    bg: {
        default: TColor;
        panel: TColor;
        float: TColor;
        active: TColor;
        disabled: TColor;
        hover: TColor;
        selection: TColor;
        search: TColor;
        contrast: TColor;

        git?: ThemeGitColorsNext<TColor>;
        feedback?: ThemeFeedbackColorsNext<TColor>;
    };

    fg: {
        default: TColor;
        subtle: TColor;
        accent: TColor;
        disabled: TColor;
        contrast: TColor;

        git?: ThemeGitColorsNext<TColor>;
        feedback?: ThemeFeedbackColorsNext<TColor>;
    };
}

/** Syntax highlighting color tokens for all language constructs. */
export interface ThemeSyntaxColorsNext<TColor = Colordx> {
    variable: {
        default: TColor;
        builtin: TColor;
        parameter: TColor;
        member: TColor;
    };
    string: {
        default: TColor;
        doc: TColor;
        regexp: TColor;
        escape: TColor;
    };
    boolean: {
        default: TColor;
    };
    number: {
        default: TColor;
    };
    property: {
        default: TColor;
    };
    constant: {
        default: TColor;
        builtin: TColor;
    };
    module: {
        default: TColor;
    };
    type: {
        default: TColor;
        builtin: TColor;
    };
    attribute: {
        default: TColor;
        builtin: TColor;
    };
    func: {
        default: TColor;
        builtin: TColor;
